"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { CheckCircle, Calendar, BarChart3, Target, Loader2 } from "lucide-react";
import { useCurrentUser } from "@/components/auth/AuthProvider";

const FEATURES = [
  {
    icon: Calendar,
    title: "Weekly Reflections",
    description: "Every Friday, take 5 minutes to share what you accomplished, what you're working on, and how you're feeling.",
  },
  {
    icon: Target,
    title: "Goals & Tasks",
    description: "Your manager will set your goals (if you're white-collar) or task scorecard (if you're blue-collar) before your first review.",
  },
  {
    icon: BarChart3,
    title: "Monthly Reviews",
    description: "On the 1st of each month, self-score your work. Your manager reviews independently. Scores are averaged — no weighting.",
  },
  {
    icon: CheckCircle,
    title: "Annual Increments",
    description: "Your 12 monthly scores average into your annual performance rating, which directly determines your increment.",
  },
];

export default function WelcomePage() {
  const router = useRouter();
  const { user, refresh } = useCurrentUser();
  const [loading, setLoading] = useState(false);

  async function handleGetStarted() {
    setLoading(true);
    try {
      await fetch("/api/auth/first-login", { method: "POST" });
      await refresh();
      router.push("/dashboard");
    } catch {
      router.push("/dashboard");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-primary-900 flex items-center justify-center p-6">
      <div className="w-full max-w-2xl">
        <div className="bg-white rounded-2xl enterprise-shadow overflow-hidden">
          {/* Header */}
          <div className="bg-primary-900 px-8 pt-8 pb-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 rounded-xl bg-accent-500 flex items-center justify-center">
                <span className="text-white font-bold text-base">CP</span>
              </div>
              <div>
                <h1 className="text-lg font-bold text-white leading-tight">Crystal People</h1>
                <p className="text-xs text-primary-300">Performance Management Platform</p>
              </div>
            </div>
            <h2 className="text-2xl font-bold text-white mb-1">
              Welcome, {user?.name?.split(" ")[0] ?? "there"}!
            </h2>
            <p className="text-primary-300 text-sm">
              Here&apos;s everything you need to know about how Crystal People works.
            </p>
          </div>

          {/* Content */}
          <div className="px-8 py-6">
            <p className="text-sm text-gray-600 mb-6">
              Crystal People is Crystal Group&apos;s internal performance platform. It replaces informal
              performance discussions with a structured, transparent, and bias-free system — for everyone,
              from operations to executives.
            </p>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
              {FEATURES.map((f) => {
                const Icon = f.icon;
                return (
                  <div key={f.title} className="rounded-xl border border-gray-100 p-4">
                    <div className="flex items-center gap-2.5 mb-2">
                      <div className="w-7 h-7 rounded-lg bg-accent-500/10 flex items-center justify-center">
                        <Icon size={15} className="text-accent-600" />
                      </div>
                      <h3 className="font-semibold text-sm text-primary-900">{f.title}</h3>
                    </div>
                    <p className="text-xs text-gray-500 leading-relaxed">{f.description}</p>
                  </div>
                );
              })}
            </div>

            <div className="rounded-xl bg-amber-50 border border-amber-200 px-4 py-3 text-sm text-amber-800 mb-6">
              <strong>What happens next:</strong> Your manager will set up your goals or task scorecard
              before the first review cycle. You&apos;ll receive a notification when everything is ready.
            </div>

            <button
              onClick={handleGetStarted}
              disabled={loading}
              className="w-full flex items-center justify-center gap-2 bg-accent-500 hover:bg-accent-600 disabled:opacity-60 text-white font-semibold py-3 px-4 rounded-lg transition-colors"
            >
              {loading ? (
                <>
                  <Loader2 size={16} className="animate-spin" />
                  Getting started...
                </>
              ) : (
                "Get Started →"
              )}
            </button>
          </div>
        </div>

        <p className="text-center text-xs text-primary-400 mt-4">
          Crystal Group — Confidential. For internal use only.
        </p>
      </div>
    </div>
  );
}
